async function seed() {
  await connectDB();

  for (const t of TIERS) await Tier.findByIdAndUpdate(t._id, t, { upsert: true });
  for (const [index, l] of LABS.entries()) {
    await Lab.findByIdAndUpdate(l._id, { ...l, sortOrder: index }, { upsert: true });
  }
  for (const a of ACHIEVEMENTS) await Achievement.findByIdAndUpdate(a._id, a, { upsert: true });

  console.log(`Seeded ${TIERS.length} tiers, ${LABS.length} labs, ${ACHIEVEMENTS.length} achievements.`);
  await disconnectDB();
}

if (require.main === module) {
  seed().catch(err => { console.error(err); process.exit(1); });
}

module.exports = { seed, TIERS, LABS, ACHIEVEMENTS };
